import React, { useState, useEffect, useRef } from 'react';
import { motion } from 'framer-motion';
import Sidebar from '../../components/Sidebar';
import Navbar from '../../components/Navbar';
import LoadingSpinner from '../../components/LoadingSpinner';
import axios from 'axios';
import toast from 'react-hot-toast';
import {
  FiUploadCloud, FiFile, FiX, FiLink,
  FiPlus, FiSend, FiClock, FiCheckCircle,
  FiPaperclip, FiImage, FiFileText
} from 'react-icons/fi';

const API = 'http://localhost:5000/api';

const getFileUrl = (filepath) => {
  const filename = filepath.split('\\').pop().split('/').pop();
  return 'http://localhost:5000/uploads/' + filename;
};

// Returns a react-icons icon component — NO emojis
const FileIcon = ({ mimetype }) => {
  if (!mimetype) return <FiFile />;
  if (mimetype.startsWith('image/')) return <FiImage />;
  if (mimetype === 'application/pdf') return <FiFileText />;
  return <FiFile />;
};

const getFileLabel = (mimetype) => {
  if (!mimetype) return 'File';
  if (mimetype.startsWith('image/')) return 'Image';
  if (mimetype === 'application/pdf') return 'PDF';
  if (mimetype.includes('word')) return 'Doc';
  if (mimetype.includes('zip') || mimetype.includes('rar')) return 'Archive';
  return 'File';
};

const SubmitAssignment = () => {
  const [assignments, setAssignments] = useState([]);
  const [mySubmissions, setMySubmissions] = useState([]);
  const [selectedAssignment, setSelectedAssignment] = useState(null);
  const [files, setFiles] = useState([]);
  const [urls, setUrls] = useState([]);
  const [urlInput, setUrlInput] = useState('');
  const [text, setText] = useState('');
  const [loading, setLoading] = useState(true);
  const [submitting, setSubmitting] = useState(false);
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [previewFile, setPreviewFile] = useState(null);
  const fileRef = useRef();

  useEffect(() => { fetchData(); }, []);

  const fetchData = async () => {
    try {
      const token = JSON.parse(localStorage.getItem('userInfo'))?.token;
      const config = { headers: { Authorization: 'Bearer ' + token } };
      const [aRes, sRes] = await Promise.all([
        axios.get(API + '/assignments', config),
        axios.get(API + '/submissions/my', config)
      ]);
      setAssignments(aRes.data);
      setMySubmissions(sRes.data);
    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  const isSubmitted = (id) =>
    mySubmissions.some(s => s.assignment?._id === id || s.assignment === id);

  const handleFileSelect = (e) =>
    setFiles(prev => [...prev, ...Array.from(e.target.files)]);

  const removeFile = (i) =>
    setFiles(prev => prev.filter((_, idx) => idx !== i));

  const addUrl = () => {
    if (urlInput.trim()) {
      setUrls(prev => [...prev, urlInput.trim()]);
      setUrlInput('');
    }
  };

  const removeUrl = (i) =>
    setUrls(prev => prev.filter((_, idx) => idx !== i));

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!selectedAssignment) return toast.error('Select an assignment');
    if (!files.length && !urls.length && !text.trim())
      return toast.error('Please add files, URLs, or text');

    setSubmitting(true);
    try {
      const token = JSON.parse(localStorage.getItem('userInfo'))?.token;
      const formData = new FormData();
      formData.append('assignment', selectedAssignment._id);
      formData.append('text', text);
      formData.append('urls', JSON.stringify(urls));
      files.forEach(f => formData.append('files', f));

      await axios.post(API + '/submissions', formData, {
        headers: {
          'Content-Type': 'multipart/form-data',
          Authorization: 'Bearer ' + token
        }
      });

      toast.success('Assignment submitted successfully!');
      setFiles([]); setUrls([]); setText(''); setSelectedAssignment(null);
      fetchData();
    } catch (err) {
      toast.error(err.response?.data?.message || 'Submission failed');
    } finally {
      setSubmitting(false);
    }
  };

  if (loading) return <LoadingSpinner />;

  return (
    <div className="page-container">
      <Sidebar isOpen={isSidebarOpen} onClose={() => setIsSidebarOpen(false)} />
      <div className="main-content" style={{ paddingTop: '90px' }}>
        <Navbar onMenuToggle={(s) => setIsSidebarOpen(s)} />

        <motion.div className="page-header" initial={{ opacity: 0, y: -20 }} animate={{ opacity: 1, y: 0 }}>
          <h1>Assignments</h1>
          <p>View and submit your assignments</p>
        </motion.div>

        <div className="content-grid">

          {/* Assignment List */}
          <motion.div initial={{ opacity: 0, x: -20 }} animate={{ opacity: 1, x: 0 }}>
            <h3 style={{ marginBottom: '15px', fontFamily: 'Poppins', color: 'var(--text-primary)' }}>
              Available Assignments
            </h3>

            {assignments.map((assignment, i) => {
              return (
                <motion.div
                  key={assignment._id}
                  className="card"
                  style={{
                    marginBottom: '12px',
                    cursor: isSubmitted(assignment._id) ? 'default' : 'pointer',
                    borderColor: selectedAssignment?._id === assignment._id ? 'var(--primary)' : undefined,
                    boxShadow: selectedAssignment?._id === assignment._id
                      ? '0 0 20px rgba(102,126,234,0.2)' : undefined
                  }}
                  onClick={() => {
                    if (!isSubmitted(assignment._id)) setSelectedAssignment(assignment);
                  }}
                  initial={{ opacity: 0, y: 10 }}
                  animate={{ opacity: 1, y: 0 }}
                  transition={{ delay: i * 0.05 }}
                  whileHover={{ scale: 1.01 }}
                >
                  <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'start' }}>
                    <div style={{ flex: 1 }}>
                      <h4 style={{ marginBottom: '6px', color: 'var(--text-primary)' }}>
                        {assignment.title}
                      </h4>
                      <p style={{ fontSize: '0.85rem', color: 'var(--text-muted)', marginBottom: '8px' }}>
                        {assignment.description?.substring(0, 100)}
                        {assignment.description?.length > 100 ? '...' : ''}
                      </p>

                      <div style={{ display: 'flex', gap: '8px', flexWrap: 'wrap' }}>
                        <span className="badge badge-primary">{assignment.subject}</span>
                        <span className="badge badge-info">
                          <FiClock size={10} /> Due: {new Date(assignment.dueDate).toLocaleDateString()}
                        </span>
                        <span className="badge badge-warning">Marks: {assignment.totalMarks}</span>
                      </div>

                      {/* Teacher attachments */}
                      {assignment.attachments && assignment.attachments.length > 0 && (
                        <div style={{ marginTop: '12px' }}>
                          <p style={{
                            fontSize: '0.72rem', color: 'var(--text-muted)',
                            textTransform: 'uppercase', letterSpacing: '0.5px',
                            marginBottom: '8px', fontWeight: '600',
                            display: 'flex', alignItems: 'center', gap: '4px'
                          }}>
                            <FiPaperclip size={10} /> Attachments
                          </p>
                          <div style={{ display: 'flex', flexWrap: 'wrap', gap: '8px' }}>
                            {assignment.attachments.map((file, idx) => {
                              const url = getFileUrl(file.filepath);
                              const isImage = file.mimetype && file.mimetype.startsWith('image/');
                              return (
                                <div key={idx} style={{ display: 'flex', flexDirection: 'column', gap: '4px' }}>
                                  {isImage && (
                                    <img
                                      src={url}
                                      alt={file.filename}
                                      onClick={(e) => { e.stopPropagation(); setPreviewFile(url); }}
                                      style={{
                                        width: '72px', height: '56px', objectFit: 'cover',
                                        borderRadius: '6px',
                                        border: '1px solid rgba(102,126,234,0.3)',
                                        cursor: 'zoom-in', display: 'block'
                                      }}
                                    />
                                  )}
                                  
                                  <a
                                    href={url}
                                    target="_blank"
                                    rel="noreferrer"
                                    onClick={(e) => { e.stopPropagation(); }}
                                    style={{
                                      display: 'inline-flex', alignItems: 'center', gap: '4px',
                                      padding: '4px 8px', borderRadius: '6px',
                                      background: 'rgba(102,126,234,0.1)',
                                      border: '1px solid rgba(102,126,234,0.25)',
                                      color: '#667eea', fontSize: '0.75rem',
                                      textDecoration: 'none', fontWeight: '500',
                                      maxWidth: '150px', overflow: 'hidden',
                                      textOverflow: 'ellipsis', whiteSpace: 'nowrap'
                                    }}
                                  >
                                    <FileIcon mimetype={file.mimetype} />
                                    {getFileLabel(file.mimetype)}: {file.filename}
                                  </a>
                                </div>
                              );
                            })}
                          </div>
                        </div>
                      )}
                    </div>

                    {isSubmitted(assignment._id) && (
                      <span className="badge badge-success" style={{ marginLeft: '10px', flexShrink: 0 }}>
                        <FiCheckCircle /> Submitted
                      </span>
                    )}
                  </div>
                </motion.div>
              );
            })}
          </motion.div>

          {/* Submit Form */}
          <motion.div initial={{ opacity: 0, x: 20 }} animate={{ opacity: 1, x: 0 }}>
            {selectedAssignment ? (
              <div className="card">
                <h3 style={{ marginBottom: '6px', fontFamily: 'Poppins' }}>
                  Submit: {selectedAssignment.title}
                </h3>
                <p style={{ fontSize: '0.82rem', color: 'var(--text-muted)', marginBottom: '20px' }}>
                  {selectedAssignment.description}
                </p>

                {/* Reference files panel */}
                {selectedAssignment.attachments && selectedAssignment.attachments.length > 0 && (
                  <div style={{
                    marginBottom: '22px', padding: '16px',
                    background: 'rgba(102,126,234,0.07)',
                    border: '1px solid rgba(102,126,234,0.2)',
                    borderRadius: '12px'
                  }}>
                    <p style={{
                      fontSize: '0.78rem', color: '#667eea', fontWeight: '700',
                      textTransform: 'uppercase', letterSpacing: '0.6px', marginBottom: '12px'
                    }}>
                      Reference Files from Teacher
                    </p>

                    <div style={{ display: 'flex', flexDirection: 'column', gap: '16px' }}>
                      {selectedAssignment.attachments.map((file, idx) => {
                        const url = getFileUrl(file.filepath);
                        const isImage = file.mimetype && file.mimetype.startsWith('image/');
                        const isPdf = file.mimetype === 'application/pdf';

                        return (
                          <div key={idx}>
                            {isImage && (
                              <img
                                src={url}
                                alt={file.filename}
                                onClick={() => setPreviewFile(url)}
                                style={{
                                  width: '100%', maxHeight: '220px',
                                  objectFit: 'cover', borderRadius: '10px',
                                  border: '1px solid rgba(102,126,234,0.25)',
                                  marginBottom: '8px', cursor: 'zoom-in', display: 'block'
                                }}
                              />
                            )}

                            {isPdf && (
                              <iframe
                                src={url}
                                title={file.filename}
                                style={{
                                  width: '100%', height: '260px',
                                  borderRadius: '10px',
                                  border: '1px solid rgba(102,126,234,0.25)',
                                  marginBottom: '8px', background: '#fff'
                                }}
                              />
                            )}

                            <a
                              href={url}
                              target="_blank"
                              rel="noreferrer"
                              style={{
                                display: 'inline-flex', alignItems: 'center', gap: '6px',
                                padding: '7px 14px', borderRadius: '8px',
                                background: 'rgba(102,126,234,0.12)',
                                border: '1px solid rgba(102,126,234,0.3)',
                                color: '#667eea', fontSize: '0.82rem',
                                textDecoration: 'none', fontWeight: '600'
                              }}
                            >
                              <FileIcon mimetype={file.mimetype} />
                              Open {file.filename}
                            </a>
                          </div>
                        );
                      })}
                    </div>
                  </div>
                )}

                {/* Submission form */}
                <form onSubmit={handleSubmit}>
                  <div className="form-group">
                    <label className="form-label">Upload Files (Photos, PDFs, Docs)</label>
                    <div className="upload-area" onClick={() => fileRef.current.click()}>
                      <FiUploadCloud className="upload-icon" />
                      <h3>Click to upload files</h3>
                      <p>Supports images, PDFs, docs (max 50MB each)</p>
                    </div>
                    <input
                      type="file"
                      ref={fileRef}
                      style={{ display: 'none' }}
                      multiple
                      onChange={handleFileSelect}
                      accept="image/*,.pdf,.doc,.docx,.zip,.rar"
                    />
                    {files.length > 0 && (
                      <div className="file-list">
                        {files.map((file, i) => (
                          <div key={i} className="file-item">
                            <div className="file-info">
                              <FiFile className="file-icon" />
                              <span style={{ fontSize: '0.85rem' }}>{file.name}</span>
                            </div>
                            <button type="button" className="remove-btn" onClick={() => removeFile(i)}>
                              <FiX />
                            </button>
                          </div>
                        ))}
                      </div>
                    )}
                  </div>

                  <div className="form-group">
                    <label className="form-label">Add URLs</label>
                    <div className="url-input-group">
                      <input
                        type="url"
                        className="form-input"
                        placeholder="https://example.com"
                        value={urlInput}
                        onChange={(e) => setUrlInput(e.target.value)}
                      />
                      <button type="button" className="btn btn-outline btn-sm" onClick={addUrl}>
                        <FiPlus />
                      </button>
                    </div>
                    {urls.length > 0 && (
                      <div className="url-list">
                        {urls.map((url, i) => (
                          <div key={i} className="url-item">
                            <a href={url} target="_blank" rel="noreferrer">
                              <FiLink /> {url}
                            </a>
                            <button type="button" className="remove-btn" onClick={() => removeUrl(i)}>
                              <FiX />
                            </button>
                          </div>
                        ))}
                      </div>
                    )}
                  </div>

                  <div className="form-group">
                    <label className="form-label">Additional Notes</label>
                    <textarea
                      className="form-textarea"
                      placeholder="Add any notes or description..."
                      value={text}
                      onChange={(e) => setText(e.target.value)}
                    />
                  </div>

                  <motion.button
                    type="submit"
                    className="btn btn-primary btn-block btn-lg"
                    disabled={submitting}
                    whileHover={{ scale: 1.02 }}
                    whileTap={{ scale: 0.98 }}
                  >
                    {submitting
                      ? <div className="loading-spinner" style={{ width: '20px', height: '20px', borderWidth: '2px' }} />
                      : <span><FiSend /> Submit Assignment</span>
                    }
                  </motion.button>
                </form>
              </div>
            ) : (
              <div className="card">
                <div className="empty-state">
                  <div className="empty-icon">
                    <FiFileText size={40} color="#667eea" />
                  </div>
                  <h3>Select an Assignment</h3>
                  <p>Click on an assignment from the list to start submitting</p>
                </div>
              </div>
            )}
          </motion.div>
        </div>
      </div>

      {/* Image Lightbox */}
      {previewFile && (
        <div
          onClick={() => setPreviewFile(null)}
          style={{
            position: 'fixed', inset: 0, zIndex: 9999,
            background: 'rgba(0,0,0,0.88)',
            display: 'flex', alignItems: 'center', justifyContent: 'center',
            cursor: 'zoom-out'
          }}
        >
          <img
            src={previewFile}
            alt="Preview"
            style={{
              maxWidth: '90vw', maxHeight: '90vh',
              borderRadius: '14px',
              border: '2px solid rgba(102,126,234,0.4)',
              boxShadow: '0 0 60px rgba(102,126,234,0.3)'
            }}
          />
          <button
            onClick={() => setPreviewFile(null)}
            style={{
              position: 'fixed', top: '20px', right: '24px',
              background: 'rgba(255,255,255,0.1)', border: 'none',
